    # --- COMPLIANCE ---
    {"text": "¿Qué es el GDPR (RGPD)?", "option_a": "Un protocolo de red", "option_b": "Reglamento de la UE para la protección de datos personales y privacidad de los ciudadanos", "option_c": "Un antivirus", "option_d": "Un tipo de firewall", "correct_answer": "b", "difficulty": "easy", "explanation": "Establece multas altísimas si las empresas no protegen adecuadamente los datos de sus clientes."},
    {"text": "¿Para qué sirve el estándar PCI-DSS?", "option_a": "Para asegurar PCs", "option_b": "Normas de seguridad para todas las entidades que procesan, almacenan o transmiten datos de tarjetas de pago", "option_c": "Un virus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "medium", "explanation": "Busca reducir el fraude con tarjetas de crédito/débito."},
    {"text": "¿Qué es la ISO 27001?", "option_a": "Una norma de calidad de cables", "option_b": "Estándar internacional para la gestión de la seguridad de la información (SGSI)", "option_c": "Un antivirus", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Ayuda a las organizaciones a gestionar sus procesos de seguridad de forma estructurada."},

    # --- INCIDENT RESPONSE ---
    {"text": "¿Cuál es la primera fase de la respuesta ante incidentes (SANS)?", "option_a": "Identificación", "option_b": "Preparación", "option_c": "Contención", "option_d": "Erradicación", "correct_answer": "b", "difficulty": "hard", "explanation": "Sin una buena preparación previa (políticas, herramientas), no se puede responder bien a un ataque."},
    {"text": "¿Qué es la 'Contención' en la respuesta ante incidentes?", "option_a": "Borrar el servidor", "option_b": "Limitar el alcance del ataque para evitar que se propague a otros sistemas", "option_c": "Llamar a la policía", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Ejemplo: desconectar el cable de red del servidor infectado."},
    {"text": "¿Qué se hace en la fase de 'Lessons Learned' (Lecciones Aprendidas)?", "option_a": "Irse a casa", "option_b": "Analizar qué falló y cómo mejorar los procesos para evitar que el incidente se repita", "option_c": "Formatear el PC", "option_d": "Un virus", "correct_answer": "b", "difficulty": "medium", "explanation": "Es la fase más olvidada pero vital para la mejora continua."},

    # --- FORENSICS ---
    {"text": "¿Qué es la 'Cadena de Custodia'?", "option_a": "Una cadena de oro", "option_b": "Registro detallado de quién ha tenido acceso a la evidencia digital desde su captura hasta el juicio", "option_c": "Un virus", "option_d": "Un tipo de cifrado", "correct_answer": "b", "difficulty": "hard", "explanation": "Si se rompe la cadena, la evidencia puede ser anulada en un tribunal."},
    {"text": "¿Qué es el 'Write Blocker' en forense?", "option_a": "Un editor de texto", "option_b": "Hardware o software que impide cualquier escritura en el disco que se está analizando para no alterar los datos", "option_c": "Un virus", "option_d": "Un error de disco", "correct_answer": "b", "difficulty": "hard", "explanation": "Garantiza la integridad de la prueba original durante el clonado."},

    # --- ADVANCED WEB ---
    {"text": "¿Qué es el SSRF (Server-Side Request Forgery)?", "option_a": "Robar el servidor", "option_b": "Ataque que permite al atacante inducir al servidor a realizar peticiones HTTP a destinos internos o externos no deseados", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Muy peligroso en nubes donde se puede consultar el servicio de metadatos del servidor."},
    {"text": "¿Qué es la 'Insecure Deserialization'?", "option_a": "Borrar archivos", "option_b": "Cuando un atacante manipula datos serializados para ejecutar código malicioso al ser reconstruidos por el servidor", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Puede llevar a la ejecución remota de código (RCE)."},

    # --- PHYSICAL SECURITY ---
    {"text": "¿Qué es una 'Mantrap'?", "option_a": "Una trampa para ratones", "option_b": "Estructura de dos puertas donde la segunda no se abre hasta que la primera se cierra, para controlar el acceso físico", "option_c": "Un virus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "medium", "explanation": "Suele usarse en la entrada de centros de datos."},
    {"text": "¿Qué es el 'Tailgating'?", "option_a": "Hacer surf", "option_b": "Seguir a una persona autorizada a través de un control de acceso sin usar credenciales propias", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Técnica física de ingeniería social muy común."},

    # --- BATCH FINAL 1 TO REACH ~110 ---
    {"text": "¿Cuál es el puerto estándar de HTTPS?", "option_a": "80", "option_b": "443", "option_c": "8080", "option_d": "21", "correct_answer": "b", "difficulty": "easy", "explanation": "Hypertext Transfer Protocol Secure."},
    {"text": "¿Qué significa CSP (Content Security Policy)?", "option_a": "Capa de Seguridad Potente", "option_b": "Cabecera HTTP que ayuda a prevenir ataques XSS permitiendo especificar qué fuentes de contenido son confiables", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Es una defensa profunda muy efectiva para webs modernas."},
    {"text": "¿Qué es el Hashing con 'Argon2'?", "option_a": "Un virus", "option_b": "Algoritmo de hash de contraseñas ganador de la Password Hashing Competition, muy resistente a ataques con GPUs", "option_c": "Un tipo de cable", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Sustituto moderno de Bcrypt y Scrypt para maxima seguridad."},
    {"text": "¿Qué es un 'Buffer Overflow'?", "option_a": "Cuando el vaso se llena", "option_b": "Error de programación que permite escribir datos fuera de los límites de un bloque de memoria memoria, pudiendo ejecutar código", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Clásico fallo de seguridad en lenguajes como C o C++."},
    {"text": "¿Qué es el 'Fuzzing'?", "option_a": "Limpiar el PC", "option_b": "Técnica de testeo que consiste en enviar datos aleatorios o malformados a un programa para encontrar fallos de seguridad", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy usado para encontrar vulnerabilidades de escalada de privilegios."},
    {"text": "¿Qué es un 'SIEM' (Security Information and Event Management)?", "option_a": "Un sistema de riego", "option_b": "Herramienta que centraliza y analiza logs de toda la red para detectar amenazas en tiempo real", "option_c": "Un virus de red", "option_d": "Un tipo de disco", "correct_answer": "b", "difficulty": "medium", "explanation": "Ejemplos: Splunk, Elastic Security, QRadar."},
    {"text": "¿Qué es un 'SOC' (Security Operations Center)?", "option_a": "Un tipo de procesador", "option_b": "Equipo y lugar físico encargado de monitorizar y defender la seguridad de la información de una empresa", "option_c": "Un manual", "option_d": "Un virus", "correct_answer": "b", "difficulty": "easy", "explanation": "Donde trabajan los analistas de seguridad de nivel 1, 2 y 3."},
    {"text": "¿Qué significa el acrónimo CVE?", "option_a": "Control de Virus Externos", "option_b": "Common Vulnerabilities and Exposures (Dase de datos de vulnerabilidades conocidas)", "option_c": "Cifrado de Videos Especiales", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Cada vulnerabilidad tiene un número único (ej: CVE-2024-XXXXX)."},

    # --- CRYPTOGRAPHIC ATTACKS ---
    {"text": "¿Qué es un 'Birthday Attack'?", "option_a": "Atacar en el cumple de alguien", "option_b": "Ataque basado en la probabilidad de encontrar colisiones en funciones hash", "option_c": "Un virus de calendario", "option_d": "Un tipo de firewall", "correct_answer": "b", "difficulty": "hard", "explanation": "Se basa en la paradoja del cumpleaños para encontrar dos entradas con el mismo hash."},
    {"text": "¿Qué es un 'Known Plaintext Attack'?", "option_a": "Ataque con texto plano", "option_b": "Ataque donde el atacante tiene acceso tanto al texto cifrado como al texto en claro correspondiente", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Ayuda a deducir la clave o el algoritmo usado."},
    {"text": "¿Qué previene un 'Replay Attack'?", "option_a": "Ver vídeos", "option_b": "Usar números de secuencia o timestamps para evitar que un atacante reenvíe una comunicación válida capturada", "option_c": "Borrar archivos", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Evita que un atacante capture un hash de password y lo vuelva a enviar para entrar."},

    # --- THREAT INTELLIGENCE ---
    {"text": "¿Qué es un 'IoC' (Indicator of Compromise)?", "option_a": "Un índice de ordenadores", "option_b": "Evidencia digital (IPs, hashes, dominios) que indica que un sistema ha sido comprometido", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Permiten a los equipos de seguridad detectar ataques conocidos rápidamente."},
    {"text": "¿Qué significan las siglas TTP en inteligencia de amenazas?", "option_a": "Todo Tiempo Perdido", "option_b": "Tactics, Techniques and Procedures (Tácticas, Técnicas y Procedimientos)", "option_c": "Tipo de Transmisión Potente", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Describe el 'modus operandi' de un grupo de atacantes (ej: APT)."},
    {"text": "¿Para qué sirve el framework MITRE ATT&CK?", "option_a": "Para cifrar discos", "option_b": "Base de datos y modelo de comportamiento de los adversarios basado en observaciones del mundo real", "option_c": "Un antivirus potente", "option_d": "Un editor de texto", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite clasificar los ataques y entender en qué fase se encuentra un intruso."},

    # --- APPLICATION SECURITY ---
    {"text": "¿Qué es el SAST (Static Application Security Testing)?", "option_a": "Test de velocidad", "option_b": "Análisis del código fuente de una aplicación sin ejecutarla para buscar vulnerabilidades", "option_c": "Un firewall por software", "option_d": "Un tipo de backup", "correct_answer": "b", "difficulty": "medium", "explanation": "Se hace durante la fase de desarrollo para encontrar fallos temprano."},
    {"text": "¿Qué es el DAST (Dynamic Application Security Testing)?", "option_a": "Test muy rápido", "option_b": "Análisis de la aplicación en tiempo de ejecución para encontrar fallos de seguridad", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Ataca la aplicación desde fuera como lo haría un hacker real."},
    {"text": "¿Qué es el 'Insecure Direct Object Reference' (IDOR)?", "option_a": "Un cable roto", "option_b": "Fallo donde un usuario puede acceder a recursos de otros simplemente cambiando un ID en la URL", "option_c": "Un virus de red", "option_d": "Un error de BIOS", "correct_answer": "b", "difficulty": "medium", "explanation": "Falta de validación de permisos en el lado del servidor."},

