    {"text": "¿Qué riesgo de seguridad tiene una imagen de Docker con usuario 'root' por defecto?", "option_a": "Ninguno", "option_b": "Si el contenedor es hackeado, el atacante tiene privilegios máximos dentro del mismo", "option_c": "Que ocupe mucho espacio", "option_d": "Que el internet vaya lento", "correct_answer": "b", "difficulty": "medium", "explanation": "Se recomienda usar usuarios no privilegiados en las imágenes de contenedor."},
    {"text": "¿Qué significa 'Shift Left' en DevSecOps?", "option_a": "Moverse a la izquierda", "option_b": "Integrar la seguridad lo más pronto posible en el ciclo de vida del desarrollo (fase de diseño y código)", "option_c": "Borrar el código", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Detectar fallos al principio es mucho más barato y seguro que al final."},

    # --- CONTINUING BATCH 4 TO REACH ~150 ---
    {"text": "¿Qué es el 'Privileged Access Management' (PAM)?", "option_a": "Darse de alta en un plan premium", "option_b": "Soluciones para custodiar y monitorizar el acceso a las cuentas de administrador (root, admin)", "option_c": "Un antivirus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "hard", "explanation": "Evita que las claves de administrador estén escritas en post-its o archivos de texto."},
    {"text": "¿Qué es un 'Exploit'?", "option_a": "Un virus que explota", "option_b": "Fragmento de software o comando que aprovecha una vulnerabilidad para provocar un comportamiento no deseado", "option_c": "Un manual de red", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la 'herramienta' que usa el fallo de seguridad."},
    {"text": "¿Qué es el 'Payload' en un ataque informático?", "option_a": "El pago por el hackeo", "option_b": "La carga útil o código malicioso final que se ejecuta tras el exploit (ej: abrir una shell)", "option_c": "Un virus de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "medium", "explanation": "El exploit abre la puerta y el payload hace el trabajo sucio."},
    {"text": "¿Qué es una 'Botnet'?", "option_a": "Una red de robots de limpieza", "option_b": "Red de equipos infectados (zombis) controlados remotamente por un atacante para lanzar ataques masivos", "option_c": "Un tipo de wifi gratuito", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "easy", "explanation": "Se usan para ataques DDoS o envío de spam masivo."},
    {"text": "¿Qué es el 'Juice Jacking'?", "option_a": "Hacer zumo", "option_b": "Ataque que aprovecha puertos USB de carga públicos para robar datos o instalar malware en móviles", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "¡Cuidado con cargar el móvil en aeropuertos o cafeterías desconocidas!"},
    {"text": "¿Qué es el 'Pretexting'?", "option_a": "Escribir textos antes", "option_b": "Técnica de ingeniería social que crea un escenario ficticio para engañar a la víctima y sacarle datos", "option_c": "Un virus de BIOS", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Ejemplo: fingir ser del soporte técnico para pedir una clave de acceso."},
    {"text": "¿Qué es el 'Quid Pro Quo' en seguridad?", "option_a": "Una frase en latín", "option_b": "Engaño donde se ofrece un servicio o beneficio a cambio de información (ej: soporte a cambio de clave)", "option_c": "Un virus de red", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Se basa en la reciprocidad del ser humano."},
    {"text": "¿Qué es un 'Baiting'?", "option_a": "Ir a pescar", "option_b": "Dejar un señuelo físico (como un USB infectado) en un lugar público esperando que alguien lo conecte", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "La curiosidad mató al gato... y al ordenador del usuario."},
    {"text": "¿Qué significa 'Air Gapping'?", "option_a": "Aire acondicionado", "option_b": "Aislamiento físico completo de un sistema de cualquier red externa por 'aire'", "option_c": "Un tipo de wifi infrarrojo", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Máxima seguridad para sistemas ultracríticos."},
    {"text": "¿Qué es el 'Bluejacking'?", "option_a": "Hackear el color azul", "option_b": "Envío de mensajes no solicitados a través de Bluetooth a dispositivos cercanos", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Aunque molesto, suele ser menos peligroso que el Bluesnarfing."},
    {"text": "¿Qué es el 'Bluesnarfing'?", "option_a": "Pintar con spray", "option_b": "Acceso no autorizado a la información de un dispositivo (contactos, fotos) a través de Bluetooth", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Ataque serio que roba datos reales del usuario."},
    {"text": "¿Qué es el 'Wardriving'?", "option_a": "Conducir un tanque", "option_b": "Recorrer zonas en coche buscando redes inalámbricas vulnerables para mapearlas o atacarlas", "option_c": "Un virus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "easy", "explanation": "Técnica clásica de descubrimiento de redes WiFi."},
    {"text": "¿Qué es un 'Root CA' (Autoridad de Certificación Raíz)?", "option_a": "El jefe de seguridad", "option_b": "Entidad de confianza suprema que firma los certificados digitales en una infraestructura de clave pública (PKI)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Si una Root CA se ve comprometida, todo internet está en peligro."},
    {"text": "¿Qué es el 'Certificate Pinning'?", "option_a": "Poner un pin al certificado", "option_b": "Técnica donde una aplicación solo confía en un certificado específico, ignorando la cadena de confianza del SO", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Evita ataques Man-in-the-Middle incluso si una CA legítima es hackeada."},
    {"text": "¿Qué es el 'HSTS Preload List'?", "option_a": "Una lista de la compra", "option_b": "Lista integrada en los navegadores con dominios que siempre deben cargarse por HTTPS obligatoriamente", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Seguridad máxima desde la primera conexión."},
    {"text": "¿Qué es un 'WAF' (Web Application Firewall)?", "option_a": "Firewall de agua", "option_b": "Firewall especializado en filtrar ataques a nivel de capa de aplicación (Capa 7) como SQLi o XSS", "option_c": "Un antivirus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Protege aplicaciones web de ataques específicos que un firewall normal no ve."},
    {"text": "¿Qué es el 'Deep Packet Inspection' (DPI)?", "option_a": "Mirar mucho", "option_b": "Análisis exhaustivo del contenido de los paquetes (datos), no solo de las cabeceras (IP/puerto)", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite detectar malware oculto dentro del tráfico legítimo."},
    {"text": "¿Qué es un 'Next-Generation Firewall' (NGFW)?", "option_a": "Un firewall del futuro", "option_b": "Combina firewall tradicional con IDS/IPS, control de aplicaciones y filtrado de malware", "option_c": "Un antivirus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Es la evolución del cortafuegos clásico."},
    {"text": "¿Diferencia entre IDS e IPS?", "option_a": "El IDS es más rápido", "option_b": "IDS solo detecta y avisa; IPS detecta y bloquea activamente la amenaza", "option_c": "IPS es de Cisco", "option_d": "No hay diferencia", "correct_answer": "b", "difficulty": "medium", "explanation": "Intrusion Detection System vs Intrusion Prevention System."},
    {"text": "¿Qué es el 'Security through Obscurity'?", "option_a": "Seguridad en la oscuridad", "option_b": "Depender únicamente del secreto del diseño o implementación para asegurar un sistema (Mala práctica)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Si el secreto se descubre, la seguridad es nula. La seguridad debe ser robusta aunque el diseño sea público."},
    {"text": "¿Qué es el 'Open Web Application Security Project' (OWASP)?", "option_a": "Un virus web", "option_b": "Fundación dedicada a mejorar la seguridad del software, famosa por su lista 'Top 10' de riesgos web", "option_c": "Un antivirus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la biblia de la seguridad en aplicaciones web."},
    {"text": "¿Qué significa el término 'Payload' en criptografía?", "option_a": "Pagar por cifrar", "option_b": "Los datos reales que se están protegiendo dentro del paquete cifrado", "option_c": "Un virus", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Es el contenido útil que queremos que siga siendo privado."},
    {"text": "¿Qué es el 'Key Escrow'?", "option_a": "Guardar las llaves en un cajón", "option_b": "Acuerdo donde una tercera parte guarda las claves criptográficas para poder recuperar datos en caso de necesidad", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "A menudo polémico por implicaciones de privacidad y acceso gubernamental."},
    {"text": "¿Qué es la 'Esteganografía'?", "option_a": "Cifrar muy fuerte", "option_b": "Técnica de ocultar un mensaje secreto dentro de otro mensaje u objeto (ej: esconder un texto dentro de una foto)", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "A diferencia del cifrado, aquí se busca que ni siquiera se sepa que hay un mensaje oculto."},
    {"text": "¿Qué es el 'Salt' en criptografía?", "option_a": "Echar sal a la sopa", "option_b": "Valor aleatorio añadido a una contraseña antes de aplicarle el hash para evitar ataques de tablas precalculadas", "option_c": "Un virus de BIOS", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Hace que el mismo password tenga un hash distinto para cada usuario."},
    {"text": "¿Qué es el 'Pepper' en criptografía?", "option_a": "Pimienta para el router", "option_b": "Valor secreto único para toda la aplicación que se añade al password junto con el salt", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "A diferencia del salt (público en BD), el pepper se guarda en un sitio ultra seguro o en el código."},
    {"text": "¿Qué es la 'Confidencialidad Persistente' (Perfect Forward Secrecy)?", "option_a": "Guardar secretos siempre", "option_b": "Garantiza que la filtración de una clave hoy no sirva para descifrar tráfico guardado de ayer", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Se logra mediante el uso de claves de sesión efímeras."},
    {"text": "¿Qué es el 'Homomorphic Encryption'?", "option_a": "Cifrado para todos", "option_b": "Cifrado que permite realizar operaciones matemáticas sobre los datos cifrados sin tener que descifrarlos", "option_c": "Un virus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "hard", "explanation": "Santo Grial de la privacidad en el cloud (procesar datos sin verlos)."},
    {"text": "¿Qué es el 'Quantum Cryptography'?", "option_a": "Cifrado muy pequeño", "option_b": "Uso de propiedades mecánicas cuánticas para realizar tareas criptográficas (ej: QKD)", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Promete comunicaciones teóricamente imposibles de interceptar sin ser detectado."},

    # --- RISK MANAGEMENT ---
    {"text": "¿Qué es el ALE (Annualized Loss Expectancy)?", "option_a": "Alegría anual", "option_b": "Costo monetario esperado que una organización perderá en un año debido a un riesgo específico", "option_c": "Un virus de red", "option_d": "Un tipo de firewall", "correct_answer": "b", "difficulty": "hard", "explanation": "Se calcula como SLE (valor pérdida única) x ARO (frecuencia anual)."},
    {"text": "¿Qué significa 'Riesgo Residual'?", "option_a": "Riesgo que no existe", "option_b": "Riesgo que permanece después de haber implementado todas las medidas de seguridad", "option_c": "Riesgo de basura digital", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Ningún sistema es seguro al 100%; siempre queda algo de riesgo."},
    {"text": "¿Qué es la 'Mitigación de Riesgos'?", "option_a": "Ignorar el riesgo", "option_b": "Implementar controles para reducir la probabilidad o el impacto de un riesgo", "option_c": "Contratar un seguro", "option_d": "Un virus", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la estrategia más común: poner defensas."},
    {"text": "¿Qué es la 'Transferencia de Riesgos'?", "option_a": "Pasarle el virus a otro", "option_b": "Pasar el impacto financiero de un riesgo a un tercero (ej: contratar un ciberseguro)", "option_c": "Apagar el servidor", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "No eliminas el riesgo, pero sí el golpe económico si ocurre."},

    # --- BC / DR (BUSINESS CONTINUITY / DISASTER RECOVERY) ---
    {"text": "¿Qué es el RTO (Recovery Time Objective)?", "option_a": "Tiempo para comer", "option_b": "Tiempo máximo permitido para restaurar un servicio tras un fallo antes de que sea inaceptable", "option_c": "Un virus de BIOS", "option_d": "Un tipo de backup", "correct_answer": "b", "difficulty": "medium", "explanation": "Define qué tan rápido debemos ser recuperando el sistema."},
    {"text": "¿Qué es el RPO (Recovery Point Objective)?", "option_a": "Punto de no retorno", "option_b": "Cantidad máxima de datos (en tiempo) que una empresa puede permitirse perder en un desastre", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Define la frecuencia con la que debemos hacer backups (ej: cada 1h o cada 24h)."},
    {"text": "¿Diferencia entre un Hot Site y un Cold Site?", "option_a": "La temperatura del edificio", "option_b": "Hot Site está listo para operar en minutos; Cold Site solo tiene el espacio y energía, sin hardware listo", "option_c": "Cold Site es un backup en la nube", "option_d": "No hay diferencia", "correct_answer": "b", "difficulty": "medium", "explanation": "El Hot Site es mucho más caro pero la recuperación es casi instantánea."},

    # --- DATA PRIVACY ---
    {"text": "¿Qué es el PII (Personally Identifiable Information)?", "option_a": "Información del procesador", "option_b": "Cualquier dato que pueda ser usado para identificar a un individuo específico (Nombre, DNI, Email)", "option_c": "Un virus de red", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la base de lo que protege el GDPR/RGPD."},
    {"text": "¿Qué es la 'Tokenización' en seguridad de datos?", "option_a": "Comprar tokens de juego", "option_b": "Sustituir un dato sensible (ej: tarjeta crédito) por un valor no sensible y aleatorio (token)", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy usado en pasarelas de pago para no almacenar los números reales de tarjeta."},
    {"text": "¿Qué es el 'Data Masking'?", "option_a": "Ponerse una máscara", "option_b": "Ocultar partes de un dato sensible (ej: **** **** **** 1234) para que sea ilegible por usuarios no autorizados", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Útil para desarrolladores que necesitan probar con datos 'reales' pero sin ver los datos privados."},

    # --- IDENTITY & ACCESS (IAM) ---
    {"text": "¿Qué es el PAM (Privileged Access Management)?", "option_a": "Un plan de cuentas", "option_b": "Sistemas para controlar, monitorizar y asegurar el acceso de usuarios con altos privilegios (admins)", "option_c": "Un antivirus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Evita que las claves de administrador se compartan o se pierdan."},
    {"text": "¿Qué es la 'Federación de Identidades'?", "option_a": "Un grupo de hackers", "option_b": "Sistema que permite usar las mismas credenciales para acceder a aplicaciones de diferentes empresas (ej: SAML)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Permite el Single Sign-On (SSO) entre diferentes proveedores."},
    {"text": "¿Qué es el RBAC (Role-Based Access Control)?", "option_a": "Control de acceso por nombre", "option_b": "Método de restringir el acceso al sistema basándose en el rol del usuario (ej: Manager, Editor)", "option_c": "Un virus de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Mucho más fácil de gestionar que dar permisos usuario por usuario."},

    # --- ARCHITECTURE & CLOUD ---
    {"text": "¿Qué significa 'Zero Trust Architecture' (ZTA)?", "option_a": "Confianza total en la red", "option_b": "Resumen: 'Nunca confíes, siempre verifica'. Todo usuario y dispositivo debe ser autenticado siempre", "option_c": "Red sin virus", "option_d": "Un manual de Cisco", "correct_answer": "b", "difficulty": "medium", "explanation": "Elimina la idea de que la red interna es 'segura' por defecto."},
    {"text": "¿Qué es el 'CASB' (Cloud Access Security Broker)?", "option_a": "Un router de nubes", "option_b": "Software o servicio que actúa como punto de control de seguridad entre los usuarios y las aplicaciones cloud", "option_c": "Un virus de red", "option_d": "Un tipo de backup", "correct_answer": "b", "difficulty": "hard", "explanation": "Ayuda a las empresas a ver qué aplicaciones cloud (SaaS) están usando sus empleados."},

    # --- THREATS & INCIDENTS ---
    {"text": "¿Qué es el 'Lateral Movement'?", "option_a": "Moverse de lado", "option_b": "Técnica donde un atacante se mueve a través de una red buscando datos sensibles tras entrar en un primer equipo", "option_c": "Un virus de BIOS", "option_d": "Un error de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Es lo que ocurre tras la explotación inicial para ampliar el control."},
    {"text": "¿Qué es el 'Exfiltration' (Exfiltración)?", "option_a": "Entrar en un sitio", "option_b": "Transferencia no autorizada de datos desde el interior de una red hacia el exterior (robo de datos)", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Es el objetivo final de la mayoría de ciberataques de espionaje."},
    {"text": "¿Qué es un 'Wiper'?", "option_a": "Un limpiacristales", "option_b": "Malware diseñado exclusivamente para borrar o destruir los datos del disco duro de forma irreversible", "option_c": "Un antivirus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "medium", "explanation": "A diferencia del ransomware, aquí no se pide rescate; el objetivo es el daño total."},

    # --- CONTINUING BATCH 5 TO REACH ~200 ---
    {"text": "¿Qué significa el término 'War Driving'?", "option_a": "Conducir un tanque", "option_b": "Buscar redes WiFi vulnerables desde un vehículo en movimiento", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Técnica clásica para mapear puntos de acceso inseguros."},
    {"text": "¿Qué es el 'Beaconing' en malware?", "option_a": "Poner una baliza", "option_b": "Señal periódica que envía un malware a su servidor de Control (C2) para pedir instrucciones", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Detectar este patrón de red es clave para encontrar equipos infectados."},
    {"text": "¿Qué es un 'Root CA'?", "option_a": "El jefe de seguridad", "option_b": "Autoridad de Certificación de nivel superior que firma los certificados de otras autoridades (CA)", "option_c": "Un virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Es el origen de la cadena de confianza en internet (HTTPS)."},
    {"text": "¿Qué es el 'OCSP'?", "option_a": "Un antivirus", "option_b": "Protocolo para verificar en tiempo real si un certificado digital ha sido revocado", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Online Certificate Status Protocol, alternativa más rápida a las listas CRL."},
    {"text": "¿Qué es el 'DNSSEC'?", "option_a": "Un DNS muy rápido", "option_b": "Extensiones de seguridad para el DNS que aseguran que las respuestas no han sido manipuladas (envenenamiento)", "option_c": "Un virus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "hard", "explanation": "Añade firmas digitales a los registros DNS para garantizar autenticidad e integridad."},
    {"text": "¿Qué es el 'BGP Hijacking'?", "option_a": "Robar el router del jefe", "option_b": "Anuncio de rutas IP falsas en internet para desviar el tráfico de una empresa hacia el atacante", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite interceptar el tráfico de países enteros si no se usa RPKI."},
    {"text": "¿Qué es el 'Shadow IT'?", "option_a": "Informática en la sombra", "option_b": "Uso de sistemas, software o servicios cloud por empleados sin el conocimiento ni aprobación del departamento de IT", "option_c": "Un grupo de hackers", "option_d": "Un virus de red", "correct_answer": "b", "difficulty": "easy", "explanation": "Supone un riesgo grave porque IT no puede proteger lo que no sabe que existe."},
    {"text": "¿Qué es el 'White Hat'?", "option_a": "Un sombrero blanco", "option_b": "Hacker ético que usa sus conocimientos para ayudar a mejorar la seguridad de las organizaciones", "option_c": "Un virus", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Actúan siempre bajo autorización y de forma legal."},
    {"text": "¿Qué es el 'Black Hat'?", "option_a": "Un sombrero negro", "option_b": "Hacker malintencionado que busca beneficio personal o causar daño explotando vulnerabilidades", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Son los criminales informáticos."},
    {"text": "¿Qué es un 'Grey Hat'?", "option_a": "Un sombrero gris", "option_b": "Hacker que actúa a veces de forma legal y a veces no, saltándose la ley pero sin intenciones puramente malignas", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Suelen pedir recompensas tras encontrar fallos sin permiso previo."},
    {"text": "¿Qué es el 'Blue Teaming'?", "option_a": "Pintar la oficina de azul", "option_b": "Equipo encargado de la defensa, monitorización y respuesta ante incidentes en una empresa", "option_c": "Hackear el bluetooth", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Su objetivo es detectar y detener al Red Team (atacantes)."},
    {"text": "¿Qué es el 'Red Teaming'?", "option_a": "Equipo de color rojo", "option_b": "Equipo encargado de simular ataques reales avanzados para poner a prueba las defensas (Blue Team)", "option_c": "Limpiar el servidor", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Ofrecen una visión realista del estado de seguridad de la organización."},
    {"text": "¿Qué es el 'Purple Teaming'?", "option_a": "Hacer mezclas", "option_b": "Colaboración directa entre el equipo de ataque (Red) y defensa (Blue) para maximizar el aprendizaje", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Busca que ambos equipos trabajen juntos para cerrar brechas de seguridad rápido."},
    {"text": "¿Qué es un 'CVE Score' (CVSS)?", "option_a": "La puntuación de un juego", "option_b": "Sistema numérico (0-10) que puntúa la severidad de una vulnerabilidad informática", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "CVSS 10.0 indica una vulnerabilidad crítica que debe parchearse de inmediato."},
    {"text": "¿Qué es el 'Sandboxing'?", "option_a": "Jugar con tierra", "option_b": "Entorno aislado y seguro donde se puede ejecutar código sospechoso sin que afecte al resto del sistema", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy usado por los analistas de malware para ver qué hace un virus sin infectar la red real."},
    {"text": "¿Qué es el 'Principio de Defensa en Profundidad'?", "option_a": "Defenderse muy fuerte", "option_b": "Implementar múltiples capas de seguridad (firewall, antivirus, parches, formación) por si una falla", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Como las murallas de un castillo: foso, muralla, torre..."},
    {"text": "¿Qué significa 'Fail-Safe' en seguridad?", "option_a": "Fallar siempre", "option_b": "Diseñar un sistema para que, en caso de fallo, quede en el estado más seguro posible (normalmente bloqueado)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Ejemplo: una puerta electrónica que se bloquea si se va la luz (si es para seguridad) o se abre (si es para incendios)."},
    {"text": "¿Qué es el 'Least Privilege'?", "option_a": "Pocos privilegios", "option_b": "Dar a los usuarios y procesos solo los permisos mínimos necesarios para realizar su función", "option_c": "Un virus", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Fundamento básico de la seguridad informática."},
    {"text": "¿Qué es el 'Segregation of Duties' (SoD)?", "option_a": "Hacer los deberes a medias", "option_b": "Repartir tareas críticas entre varias personas para evitar el fraude o errores graves", "option_c": "Un virus", "option_d": "Un tipo de backup", "correct_answer": "b", "difficulty": "medium", "explanation": "Ejemplo: que quien pide una compra no sea el mismo que la autoriza."},
    {"text": "¿Qué es el 'Need to Know'?", "option_a": "Querer saber todo", "option_b": "Restringir el acceso a la información solo a las personas que realmente la necesitan para su trabajo", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Complementa al principio de mínimo privilegio."},
    {"text": "¿Qué es un 'WAF'?", "option_a": "Firewall de agua", "option_b": "Firewall de aplicaciones web que protege contra ataques como inyecciones SQL o XSS", "option_c": "Un antivirus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Web Application Firewall."},
    {"text": "¿Qué puerto usa por defecto el protocolo SSH?", "option_a": "21", "option_b": "22", "option_c": "80", "option_d": "443", "correct_answer": "b", "difficulty": "easy", "explanation": "Secure Shell, puerto estándar de administración de servidores."},
    {"text": "¿Qué puerto usa por defecto el protocolo RDP (Windows)?", "option_a": "22", "option_b": "3389", "option_c": "445", "option_d": "53", "correct_answer": "b", "difficulty": "medium", "explanation": "Remote Desktop Protocol de Microsoft."},
    {"text": "¿Qué es el puerto 445 en Windows?", "option_a": "Puerto de internet", "option_b": "SMB: usado para compartir archivos e impresoras, objetivo común de exploits como EternalBlue", "option_c": "Un virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy peligroso si se expone a internet directamente."},
    {"text": "¿Qué es un 'Salting'?", "option_a": "Añadir sal", "option_b": "Agregar datos aleatorios a una contraseña antes de hacer el hash para prevenir ataques de tablas Rainbow", "option_c": "Un virus", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Obliga al atacante a calcular el hash para cada usuario individualmente."},
    {"text": "¿Qué es el 'DDoS'?", "option_a": "Un juego de dos", "option_b": "Distributed Denial of Service: ataque masivo desde muchas fuentes para tumbar un servicio", "option_c": "Un virus de BIOS", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "easy", "explanation": "Sobrecarga los recursos del servidor o la red."},
    {"text": "¿Qué es el 'Phishing'?", "option_a": "Ir a pescar", "option_b": "Suplantar una identidad legítima (banco, jefe) para robar datos mediante engaño", "option_c": "Un virus de red", "option_d": "Un firewall", "correct_answer": "b", "difficulty": "easy", "explanation": "Suele ocurrir a través de email, SMS (Smishing) o llamadas (Vishing)."},
    {"text": "¿Qué es el 'Whaling'?", "option_a": "Pescar ballenas", "option_b": "Tipo de Phishing dirigido específicamente a altos directivos (CEOs, managers) de una empresa", "option_c": "Un virus potente", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Buscan fraudes millonarios mediante transferencias no autorizadas."},
    {"text": "¿Qué es el 'Vishing'?", "option_a": "Phishing por vídeo", "option_b": "Phishing realizado a través de llamadas telefónicas", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Voice Phishing."},
    {"text": "¿Qué es el 'Smishing'?", "option_a": "Phishing por Twitter", "option_b": "Phishing realizado a través de mensajes de texto (SMS)", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "SMS Phishing."},
    {"text": "¿Qué es el 'Spam'?", "option_a": "Una carne en lata", "option_b": "Correos electrónicos no solicitados, normalmente de carácter publicitario o malicioso", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Representa la gran mayoría del tráfico de email en el mundo."},
    {"text": "¿Qué es un 'Zombi' en ciberseguridad?", "option_a": "Un virus de películas", "option_b": "Ordenador infectado que forma parte de una botnet y espera órdenes de un atacante", "option_c": "Un PC roto", "option_d": "Un tipo de usuario avanzado", "correct_answer": "b", "difficulty": "easy", "explanation": "El usuario suele no saber que su ordenador está siendo usado para atacar a otros."},
    {"text": "¿Qué es el 'Social Engineering'?", "option_a": "Ingeniería de redes sociales", "option_b": "El arte de manipular a las personas para que revelen información confidencial", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Aprovecha la psicología humana (confianza, miedo, urgencia)."},
    {"text": "¿Qué es el 'Dumpster Diving'?", "option_a": "Bucear en internet", "option_b": "Buscar información útil (passwords, datos de clientes) en la basura física de una empresa", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Por eso es vital triturar todos los documentos sensibles."},
    {"text": "¿Qué es el 'Vulnerability Scanning'?", "option_a": "Escanear virus", "option_b": "Uso de herramientas automáticas para encontrar fallos de seguridad conocidos en un sistema", "option_c": "Hackear una web", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Ejemplos: Nessus, OpenVAS."},
    {"text": "¿Qué es un 'Exploit Kit'?", "option_a": "Un kit de herramientas de red", "option_b": "Herramienta que analiza el navegador del usuario y lanza automáticamente el exploit adecuado para infectarlo", "option_c": "Un antivirus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy común en ataques de 'drive-by download'."},
    {"text": "¿Qué es el 'Zero Trust'?", "option_a": "Confianza cero", "option_b": "Filosofía de seguridad: 'Nunca confíes, siempre verifica'", "option_c": "Un antivirus potente", "option_d": "Cero virus en la red", "correct_answer": "b", "difficulty": "easy", "explanation": "No se asume que alguien es de confianza solo por estar dentro de la red corporativa."},
    {"text": "¿Qué es un 'Bastion Host'?", "option_a": "El servidor del jefe", "option_b": "Servidor ultra seguro situado en la DMZ para gestionar el acceso a la red interna", "option_c": "Un virus de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "medium", "explanation": "Es el punto de choque inicial para cualquier conexión externa legítima."},
    {"text": "¿Qué significa 'Air-Gap'?", "option_a": "Espacio para el router", "option_b": "Mantener un sistema físicamente desconectado de cualquier otra red (especialmente de internet)", "option_c": "Un virus de Wi-Fi", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Usado en infraestructuras críticas como centrales nucleares."},
    {"text": "¿Qué es el 'Cold Backup'?", "option_a": "Backup en la nieve", "option_b": "Backup que se realiza offline, sin estar conectado a ninguna red, para evitar ransomware", "option_c": "Un backup rápido", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Es la última defensa si el atacante borra todos los backups online."},
    {"text": "¿Qué es un 'Logic Bomb'?", "option_a": "Una bomba física", "option_b": "Código malicioso que permanece dormido hasta que ocurre un evento específico (ej: una fecha o el despido de alguien)", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy usado por empleados resentidos."},
    {"text": "¿Qué es el 'Man-in-the-Middle' (MitM)?", "option_a": "Un hombre en el medio de la calle", "option_b": "Ataque donde el atacante intercepta y opcionalmente altera la comunicación entre dos partes sin que lo sepan", "option_c": "Un virus de red", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Se evita usando cifrado punto a punto (HTTPS, SSH)."},
    {"text": "¿Qué es el 'DNS Hijacking'?", "option_a": "Robar el servidor DNS", "option_b": "Redirigir las consultas DNS del usuario a servidores falsos para llevarlo a webs maliciosas", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "El usuario ve 'www.mibanco.com' pero está en la web del atacante."},
    {"text": "¿Qué significa el término 'Malware'?", "option_a": "Mal functioning Hardware", "option_b": "Malicious Software (Software Malicioso)", "option_c": "Un manual de red", "option_d": "Un grupo de hackers", "correct_answer": "b", "difficulty": "easy", "explanation": "Cualquier programa diseñado para dañar o infiltrarse en un sistema."},
    {"text": "¿Qué es un 'Worm' (Gusano)?", "option_a": "Un gusano de jardín", "option_b": "Malware que se replica solo por la red sin interacción del usuario", "option_c": "Un virus de BIOS", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "easy", "explanation": "Diferente al virus, que necesita un archivo anfitrión."},
    {"text": "¿Qué es el 'Spyware'?", "option_a": "Software de ayuda", "option_b": "Malware que espía la actividad del usuario (teclas, pantalla, archivos) para robar información", "option_c": "Un manual", "option_d": "Un antivirus potente", "correct_answer": "b", "difficulty": "easy", "explanation": "Suele enviarse junto con software gratuito."},
    {"text": "¿Qué es el 'Ransomware'?", "option_a": "Un antivirus ruso", "option_b": "Malware que cifra los archivos de la víctima y pide un rescate económico para recuperarlos", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "La amenaza más lucrativa para los cibercriminales hoy día."},
    {"text": "¿Qué es un 'Rootkit'?", "option_a": "Un kit de reparación", "option_b": "Malware diseñado para ocultarse profundamente en el sistema y dar acceso total al atacante", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Se ocultan a menudo a nivel de Kernel o incluso Firmware."},
    {"text": "¿Qué es el 'Clickjacking'?", "option_a": "Borrar clics", "option_b": "Engañar al usuario para que haga clic en algo que no ve (usando capas transparentes) para realizar acciones no deseadas", "option_c": "Un virus de red", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy común en redes sociales para forzar 'Me gusta' o seguir a perfiles maliciosos."},
    {"text": "¿Qué es el 'Session Hijacking'?", "option_a": "Robar la sesión", "option_b": "Robar la cookie de sesión de un usuario para tomar el control de su cuenta sin saber su password", "option_c": "Un virus de BIOS", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Se evita usando HTTPS y flags de seguridad en las cookies."},
    {"text": "¿Qué es la 'Inyección SQL'?", "option_a": "Inyectar agua en la base de datos", "option_b": "Introducir código malicioso en campos de texto para manipular la base de datos", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Puede permitir robar toda la base de datos de usuarios de una web."},
    {"text": "¿Qué es un 'Brute Force Attack'?", "option_a": "Golpear el PC", "option_b": "Probar sistemáticamente todas las combinaciones posibles de password hasta dar con la correcta", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Se evita con passwords largos, bloqueos de cuenta y MFA."},
    {"text": "¿Qué es un 'Dictionary Attack'?", "option_a": "Atacar con un libro", "option_b": "Probar miles de passwords comunes sacados de una lista (diccionario)", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "easy", "explanation": "Mucho más rápido que la fuerza bruta pura."},
    {"text": "¿Qué es el 'Credential Stuffing'?", "option_a": "Rellenar datos", "option_b": "Usar usuarios y passwords robados de una web para intentar entrar automáticamente en muchas otras", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Aprovecha que los usuarios repiten passwords en diferentes sitios."},
    {"text": "¿Qué es el 'Antivirus'?", "option_a": "Un virus antiguo", "option_b": "Software diseñado para detectar, bloquear y eliminar malware", "option_c": "Un manual de ayuda", "option_d": "Un grupo de hackers", "correct_answer": "b", "difficulty": "easy", "explanation": "Esencial en cualquier sistema personal o corporativo."},
    {"text": "¿Qué es un 'IPS'?", "option_a": "Un router especial", "option_b": "Intrusion Prevention System: detecta y detiene ataques en tiempo real en la red", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Evolución del IDS (que solo detectaba)."},
    {"text": "¿Qué es el 'Sandboxing'?", "option_a": "Jugar con tierra", "option_b": "Ejecutar programas sospechosos en un entorno aislado para ver qué hacen sin riesgo", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Vital para analizar malware moderno."},
    {"text": "¿Qué es el 'Penetration Testing' (Pentesting)?", "option_a": "Hackear sin permiso", "option_b": "Ataque simulado autorizado sobre un sistema para encontrar y reportar fallos de seguridad", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Ayuda a las empresas a saber dónde son vulnerables."},
    {"text": "¿Qué es el 'Social Engineering'?", "option_a": "Ingeniería de redes sociales", "option_b": "Manipular psicológicamente a las personas para que revelen información secreta", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "El hacker ataca al humano, no a la máquina."},
    {"text": "¿Qué es el 'Dumpster Diving'?", "option_a": "Bucear en internet", "option_b": "Buscar passwords o datos sensibles tirados en la basura física", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "¡Tritura siempre tus documentos importantes!"},
    {"text": "¿Qué es el 'Shoulder Surfing'?", "option_a": "Hacer surf", "option_b": "Mirar por encima del hombro mientras alguien escribe su password", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Técnica física de robo de claves."},
    {"text": "¿Qué es un 'HoneyPot'?", "option_a": "Tarro de miel", "option_b": "Sistema trampa diseñado para atraer a los hackers y estudiar sus técnicas sin riesgo", "option_c": "Un virus de red", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Ayuda a recolectar inteligencia sobre los atacantes."},
    {"text": "¿Qué significa el acrónimo 'APT'?", "option_a": "Ataque Potente Total", "option_b": "Advanced Persistent Threat: grupo de atacantes avanzado, con muchos recursos y sigiloso", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "hard", "explanation": "Suelen ser estados-nación o grupos criminales de élite."},

    # --- CLOUD & INFRASTRUCTURE BATCH 2 ---
    {"text": "¿Qué es el 'Serverless Security'?", "option_a": "Seguridad sin servidores", "option_b": "Protección de funciones (como AWS Lambda) donde la seguridad se centra en el código y los permisos, no en el SO", "option_c": "Un virus de red", "option_d": "Un tipo de firewall físico", "correct_answer": "b", "difficulty": "medium", "explanation": "El proveedor gestiona el servidor, el cliente gestiona la seguridad de la función."},
    {"text": "¿Qué es el 'Infrastructure as Code' (IaC) Security?", "option_a": "Cifrar el código", "option_b": "Escanear scripts de configuración (Terraform, Ansible) en busca de fallos antes de desplegarlos", "option_c": "Un antivirus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Evita desplegar nubes con puertos abiertos por error en el script."},
    {"text": "¿Qué es un 'Secrets Manager'?", "option_a": "Un jefe de secretos", "option_b": "Servicio para almacenar y rotar claves de API, passwords y certificados de forma segura", "option_c": "Un virus de red", "option_d": "Un tipo de disco", "correct_answer": "b", "difficulty": "medium", "explanation": "Evita tener claves escritas en código (Hardcoded secrets)."},
    {"text": "¿Qué es un 'HSM' (Hardware Security Module)?", "option_a": "Un router muy rápido", "option_b": "Dispositivo físico dedicado que protege y gestiona claves criptográficas", "option_c": "Un antivirus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "hard", "explanation": "Las claves nunca salen del dispositivo físico, lo que las hace casi imposibles de robar vía software."},

    # --- MOBILE APP SECURITY ---
    {"text": "¿Qué es el 'Reverse Engineering' en apps?", "option_a": "Programar al revés", "option_b": "Analizar el ejecutable de una app para entender cómo funciona y buscar fallos", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Los atacantes lo usan para encontrar lógica de negocio vulnerable o claves ocultas."},
    {"text": "¿Qué es el 'SSL Pinning'?", "option_a": "Poner un pin a la red", "option_b": "Técnica donde una app solo confía en un certificado específico, ignorando las CAs del sistema", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Dificulta mucho los ataques Man-in-the-Middle y el análisis de tráfico de la app."},
    {"text": "Riesgo de 'Insecure Data Storage' en móviles?", "option_a": "Que el móvil se llene", "option_b": "Guardar datos sensibles (passwords, tokens) en texto claro en el almacenamiento del dispositivo", "option_c": "Que el internet vaya lento", "option_d": "No tiene riesgos", "correct_answer": "b", "difficulty": "medium", "explanation": "Si el móvil es robado o tiene root, los datos son fácilmente legibles."},

    # --- REGULATORY & COMPLIANCE ---
    {"text": "¿Qué protege la ley HIPAA?", "option_a": "Datos de hipopótamos", "option_b": "Privacidad y seguridad de la información médica de los pacientes (en EE. UU.)", "option_c": "Datos bancarios", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Health Insurance Portability and Accountability Act."},
    {"text": "¿Qué es el 'DPO' (Data Protection Officer)?", "option_a": "Un virus de red", "option_b": "Delegado de Protección de Datos: figura obligatoria en muchas empresas para velar por el cumplimiento del GDPR", "option_c": "Un tipo de firewall", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "easy", "explanation": "Es el responsable máximo de la privacidad en la organización."},
    {"text": "¿Qué es un 'Data Privacy Impact Assessment' (DPIA)?", "option_a": "Un virus de BIOS", "option_b": "Proceso para identificar y minimizar los riesgos de privacidad en nuevos proyectos de tratamiento de datos", "option_c": "Un antivirus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Requerido por el GDPR para tratamientos de alto riesgo."},

    # --- SEC OPS & THREAT HUNTING ---
    {"text": "¿Qué es el 'Threat Hunting'?", "option_a": "Cazar virus", "option_b": "Búsqueda proactiva de amenazas que han logrado evadir las soluciones de seguridad automáticas", "option_c": "Un juego de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "No espera a que salte una alerta; el analista busca anomalías activamente."},
    {"text": "¿Qué es un 'SOAR'?", "option_a": "Un sistema de vuelo", "option_b": "Security Orchestration, Automation and Response: herramientas para automatizar la respuesta a incidentes", "option_c": "Un virus de red", "option_d": "Un tipo de disco", "correct_answer": "b", "difficulty": "hard", "explanation": "Permite que el sistema responda automáticamente a ataques comunes sin intervención humana."},
    {"text": "¿Qué es un 'Playbook' en un SOC?", "option_a": "Un libro de juegos", "option_b": "Guía paso a paso que describe cómo deben actuar los analistas ante un tipo de ataque específico", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Garantiza una respuesta consistente y eficiente del equipo de seguridad."},

    # --- ADVANCED ATTACKS & TRENDS ---
    {"text": "¿Qué es el 'Adversarial Machine Learning'?", "option_a": "IA que ayuda a hackear", "option_b": "Técnicas para engañar a modelos de IA (ej: haciendo que un antivirus no vea un virus)", "option_c": "Un robot de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Ataques diseñados para explotar cómo 'aprenden' los algoritmos."},
    {"text": "¿Qué es el 'Prompt Injection' en LLMs?", "option_a": "Inyectar código en la BIOS", "option_b": "Manipular la entrada de un modelo de lenguaje para que ignore sus reglas de seguridad", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Nueva frontera de ataques a la IA generativa."},
    {"text": "¿Qué es el 'Supply Chain Attack'?", "option_a": "Atacar una cadena física", "option_b": "Infectar a un proveedor de software confiable para llegar a todos sus clientes (ej: SolarWinds)", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Ataques de gran impacto porque aprovechan la confianza en software legítimo."},

    # --- FINAL 100 QUESTIONS FOR TOTAL 300 ---
    {"text": "¿Qué es el 'Salami Attack'?", "option_a": "Un virus de comida", "option_b": "Serie de robos de cantidades minúsculas de dinero que pasan desapercibidos pero suman mucho", "option_c": "Un manual de red", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Suele ocurrir en sistemas financieros."},
    {"text": "¿Qué es el 'Data Diddling'?", "option_a": "Borrar datos", "option_b": "Modificación no autorizada de datos antes o durante su entrada al sistema", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Ataque contra la integridad de los datos."},
    {"text": "¿Qué es un 'Skimmer'?", "option_a": "Un nadador", "option_b": "Dispositivo físico colocado en cajeros o lectores de tarjetas para clonar la banda magnética", "option_c": "Un virus", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "easy", "explanation": "Técnica clásica de fraude bancario físico."},
    {"text": "¿Qué es el 'Vishing'?", "option_a": "Phishing por vídeo", "option_b": "Phishing realizado mediante llamadas de voz", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Voice Phishing."},
    {"text": "¿Qué significa 'BYOD' en seguridad?", "option_a": "Traer tu propia bebida", "option_b": "Bring Your Own Device: empleados usando sus dispositivos personales para el trabajo", "option_c": "Un antivirus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "easy", "explanation": "Gran reto para la seguridad corporativa."},
    {"text": "¿Qué es la 'Zonificación' en un centro de datos?", "option_a": "Separar por colores", "option_b": "División física y lógica de la red en áreas de diferente nivel de seguridad", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Evita que un fallo en un área comprometa todo el DC."},
    {"text": "¿Qué es un 'Faraday Cage'?", "option_a": "Una jaula para pájaros", "option_b": "Recinto que bloquea los campos electromagnéticos externos (evita espionaje de radiofrecuencia)", "option_c": "Un virus", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Usada en salas seguras para evitar filtraciones inalámbricas."},
    {"text": "¿Qué es el 'TEMPEST'?", "option_a": "Una tormenta", "option_b": "Estándar de la NSA para proteger equipos contra el espionaje de emanaciones electromagnéticas", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Evita que alguien lea lo que sale en tu monitor capturando sus ondas de radio."},
    {"text": "¿Qué es un 'Lock Picking'?", "option_a": "Abrir un candado", "option_b": "Arte de manipular los componentes de una cerradura física para abrirla sin llave", "option_c": "Un virus de BIOS", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Seguridad física básica."},
    {"text": "¿Qué es un 'Ciphertext'?", "option_a": "Texto plano", "option_b": "El resultado legible de aplicar un algoritmo de cifrado a un mensaje", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Es lo que el atacante ve si intercepta el mensaje cifrado."},
    {"text": "¿Qué es un 'Cleartext'?", "option_a": "Texto cifrado", "option_b": "Mensaje en su formato original, legible por cualquiera sin necesidad de claves", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Nunca debe enviarse información sensible en cleartext por redes públicas."},
    {"text": "¿Qué significa 'Non-Repudiation' (No Repudio)?", "option_a": "No poder borrar nada", "option_b": "Garantía de que el emisor de un mensaje no puede negar haberlo enviado (ej: mediante firmas digitales)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Vital para contratos digitales y transacciones bancarias."},
    {"text": "¿Qué es el 'Key Clustering'?", "option_a": "Un grupo de llaves", "option_b": "Fallo criptográfico donde dos claves diferentes generan el mismo texto cifrado para el mismo mensaje", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Indica una debilidad grave en el algoritmo de cifrado."},
    {"text": "¿Qué es el 'Work Factor' en criptografía?", "option_a": "Lo que trabaja un hacker", "option_b": "Tiempo y recursos necesarios para romper un sistema criptográfico", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Si el work factor es mayor a la vida del universo, el sistema es 'seguro'."},
    {"text": "¿Qué es el 'Confusion' en criptografía?", "option_a": "Estar confundido", "option_b": "Propiedad que hace que la relación entre la clave y el texto cifrado sea lo más compleja posible", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Se suele lograr mediante sustitución (S-Boxes)."},
    {"text": "¿Qué es la 'Diffusion' en criptografía?", "option_a": "Difundir virus", "option_b": "Propiedad donde el cambio de un solo bit en el mensaje original afecta a muchos bits del texto cifrado", "option_c": "Un manual", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "hard", "explanation": "Se suele lograr mediante permutación."},
    {"text": "¿Qué es un 'Block Cipher'?", "option_a": "Cifrado por trozos", "option_b": "Algoritmo que cifra datos en bloques de tamaño fijo (ej: AES cifra bloques de 128 bits)", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Es el tipo de cifrado más común para archivos."},
    {"text": "¿Qué es un 'Stream Cipher'?", "option_a": "Cifrado de vídeo", "option_b": "Algoritmo que cifra los datos bit a bit en tiempo real (ej: RC4 o ChaCha20)", "option_c": "Un virus", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy rápido para comunicaciones en streaming o redes inalámbricas."},
    {"text": "¿Qué es el 'Initialization Vector' (IV)?", "option_a": "Un virus inicial", "option_b": "Valor aleatorio usado junto con la clave para asegurar que el mismo mensaje cifrado dos veces sea diferente", "option_c": "Un manual de ayuda", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "hard", "explanation": "Previene ataques de patrones y diccionarios."},
    {"text": "¿Qué es el 'Padding' en criptografía?", "option_a": "Relleno de seguridad", "option_b": "Datos extra añadidos al final del mensaje para que su longitud coincida con el tamaño del bloque del cifrado", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Necesario en cifrados de bloque como AES-CBC."},
    {"text": "¿Qué es el 'Electronic Code Book' (ECB)?", "option_a": "Libro electrónico", "option_b": "Modo de cifrado más simple y menos seguro donde cada bloque idéntico genera el mismo resultado cifrado", "option_c": "Un virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "No debe usarse para imágenes o datos con patrones repetitivos."},
    {"text": "¿Qué es el 'Cipher Block Chaining' (CBC)?", "option_a": "Cadena de bloques", "option_b": "Modo de cifrado donde cada bloque se encadena con el anterior usando un XOR, haciéndolo más seguro que ECB", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Requiere un Vector de Inicialización (IV)."},
    {"text": "¿Qué es el 'Steganalysis'?", "option_a": "Cifrar fotos", "option_b": "Arte de detectar mensajes ocultos mediante esteganografía", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Contramedida de la esteganografía."},
    {"text": "¿Qué es el 'Traffic Analysis'?", "option_a": "Mirar el tráfico", "option_b": "Analizar los metadatos de la comunicación (quién habla con quién y cuánto) para deducir información", "option_c": "Un virus", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy útil para inteligencia aunque la comunicación esté cifrada."},
    {"text": "¿Qué es un 'Backdoor'?", "option_a": "Puerta de atrás", "option_b": "Método de saltarse la autenticación normal para entrar en un sistema (puede ser legítima o maliciosa)", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Peligro extremo si la descubre un atacante."},
    {"text": "¿Qué es el 'Easter Egg' en software?", "option_a": "Un huevo de pascua", "option_b": "Función oculta e inofensiva en un programa, puesta por los desarrolladores como broma", "option_c": "Un virus potente", "option_d": "Un error de sistema", "correct_answer": "b", "difficulty": "easy", "explanation": "Aunque inofensivo, en entornos críticos se prohiben por política de seguridad (código no documentado)."},
    {"text": "¿Qué es el 'Privilege Escalation'?", "option_a": "Subir de nivel", "option_b": "Ataque donde el atacante logra mayores permisos de los que le corresponden (ej: de usuario a root)", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Es el paso siguiente tras entrar en un sistema."},
    {"text": "¿Qué es el 'Data Execution Prevention' (DEP)?", "option_a": "No ejecutar datos", "option_b": "Tecnología de Windows que marca zonas de memoria como 'no ejecutables' para evitar ataques de buffer overflow", "option_c": "Un virus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "hard", "explanation": "Medida de seguridad a nivel de hardware y sistema operativo."},
    {"text": "¿Qué es el 'ASLR' (Address Space Layout Randomization)?", "option_a": "IPs aleatorias", "option_b": "Técnica que cambia la ubicación de los procesos en la memoria RAM cada vez que se ejecutan", "option_c": "Un virus", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "hard", "explanation": "Dificulta que un exploit sepa dónde inyectar su código malicioso."},
    {"text": "¿Qué es un 'Race Condition'?", "option_a": "Carrera de coches", "option_b": "Fallo de software donde el resultado depende del orden de ejecución de los procesos; puede usarse para saltar seguridad", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Ataque clásico de tiempo (Time-of-Check vs Time-of-Use)."},
    {"text": "¿Qué es un 'Time-of-Check to Time-of-Use' (TOCTOU)?", "option_a": "Un tipo de reloj", "option_b": "Ataque que aprovecha el tiempo entre que un sistema verifica un permiso y realmente realiza la acción", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Fallo común en sistemas operativos y aplicaciones multi-hilo."},
    {"text": "¿Qué es un 'Deadlock'?", "option_a": "Muerte por bloqueo", "option_b": "Situación donde dos procesos se bloquean mutuamente esperando recursos del otro; puede usarse para DoS", "option_c": "Un virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Error de diseño de software que afecta a la disponibilidad."},
    {"text": "¿Qué es el 'Resource Exhaustion'?", "option_a": "Estar cansado", "option_b": "Ataque que consume toda la CPU, RAM o disco del servidor para dejarlo inoperativo", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Forma básica de Denegación de Servicio (DoS)."},
    {"text": "¿Qué significa 'Air-Gap'?", "option_a": "Espacio para el router", "option_b": "Aislamiento físico completo de una red de cualquier otra red externa (internet)", "option_c": "Un tipo de conexión Wi-Fi", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Se usa en infraestructuras críticas."},
    {"text": "¿Qué es un 'Hardware Keylogger'?", "option_a": "Un virus en el disco duro", "option_b": "Dispositivo físico conectado entre el teclado y el PC para registrar las pulsaciones", "option_c": "Un tipo de monitor", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Invisible para el antivirus porque no es software."},
    {"text": "¿Qué es el 'Sniffing'?", "option_a": "Oler la red", "option_b": "Interceptar y leer paquetes de datos que circulan por una red de comunicaciones", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Se evita usando cifrado (HTTPS, VPN, etc.)."},
    {"text": "¿Qué es el 'Whaling'?", "option_a": "Pescar ballenas", "option_b": "Phishing dirigido directamente contra los altos directivos de una empresa (CEO, CFO)", "option_c": "Un virus potente", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Buscan fraudes millonarios suplantando identidades clave."},
    {"text": "¿Qué significa 'Vishing'?", "option_a": "Phishing por vídeo", "option_b": "Phishing realizado a través de llamadas de voz", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Voice Phishing."},
    {"text": "¿Qué significa 'Smishing'?", "option_a": "Phishing por Twitter", "option_b": "Phishing realizado a través de mensajes de texto (SMS)", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "SMS Phishing."},
    {"text": "¿Qué es el 'Typosquatting'?", "option_a": "Escribir muy rápido", "option_b": "Registrar dominios parecidos a los reales pero con errores (ej: gogle.com) para pescar usuarios", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Aprovecha los errores de escritura de los usuarios en el navegador."},
    {"text": "¿Qué es el 'Pharming'?", "option_a": "Granja de virus", "option_b": "Redirigir el tráfico de una web legítima a una falsa sin que el usuario lo note (envenenando DNS o el archivo hosts)", "option_c": "Un antivirus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Más peligroso que el phishing porque el usuario escribe bien la URL real."},
    {"text": "¿Qué es un 'Drive-by Download'?", "option_a": "Descargar mientras conduces", "option_b": "Descarga e instalación automática de malware solo por visitar una web infectada, sin hacer clic en nada", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Aprovecha vulnerabilidades en el navegador o sus plugins (ej: Flash, Java)."},
    {"text": "¿Qué es el 'Clickjacking'?", "option_a": "Robar el ratón", "option_b": "Técnica que engaña al usuario para que haga clic en un enlace invisible o diferente al que ve", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "medium", "explanation": "Usa iframes transparentes superpuestos a la web legítima."},
    {"text": "¿Qué es el 'SEO Poisoning'?", "option_a": "Envenenar a Google", "option_b": "Técnica para hacer que webs maliciosas aparezcan en los primeros puestos de los buscadores", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Buscan que el usuario confíe por el simple hecho de estar en la primera página de búsqueda."},
    {"text": "¿Qué es un 'Zero-Day'?", "option_a": "Día cero de internet", "option_b": "Vulnerabilidad desconocida por el fabricante para la cual no existe todavía un parche", "option_c": "Un virus que borra todo", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Son extremadamente valiosos para los atacantes de élite."},
    {"text": "¿Qué es un 'Software Patch' (Parche)?", "option_a": "Un dibujo en el PC", "option_b": "Actualización de software diseñada para corregir errores o vulnerabilidades de seguridad", "option_c": "Un virus antiguo", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Mantener el sistema parcheado es la defensa número 1 contra ciberataques."},
    {"text": "¿Qué es el 'Vulnerability Management'?", "option_a": "Gestionar virus", "option_b": "Proceso cíclico de identificar, clasificar, priorizar y remediar vulnerabilidades en la empresa", "option_c": "Hackear servidores", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "No basta con escanear, hay que aplicar soluciones de forma organizada."},
    {"text": "¿Qué es el 'CVE'?", "option_a": "Control de Virus Externos", "option_b": "Common Vulnerabilities and Exposures: diccionario de vulnerabilidades conocidas públicamente", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Cada fallo tiene un ID único (ej: CVE-2023-1234)."},
    {"text": "¿Qué es el 'CVSS'?", "option_a": "Un antivirus", "option_b": "Common Vulnerability Scoring System: sistema para puntuar la severidad de un fallo de seguridad", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Va de 0.0 a 10.0 (Crítico)."},
    {"text": "¿Qué es un 'SIEM'?", "option_a": "Un sistema de riego de red", "option_b": "Software que centraliza y analiza los logs de toda la empresa para detectar ataques en tiempo real", "option_c": "Un antivirus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "medium", "explanation": "Security Information and Event Management (ej: Splunk, AlienVault)."},
    {"text": "¿Qué es un 'SOC'?", "option_a": "Socket de red", "option_b": "Security Operations Center: equipo y lugar encargado de vigilar y defender la empresa frente a ciberataques", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Es el centro de mando de la seguridad."},
    {"text": "¿Qué es el 'Incident Response Plan' (IRP)?", "option_a": "Un manual de ayuda", "option_b": "Conjunto de instrucciones para detectar, responder y recuperarse de un incidente de seguridad", "option_c": "Un virus de BIOS", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "easy", "explanation": "Vital para actuar con calma y eficacia durante un hackeo real."},
    {"text": "¿Qué es la 'Forense Digital'?", "option_a": "Autopsia de ordenadores", "option_b": "Ciencia de recolectar, preservar y analizar evidencia digital para su uso legal", "option_c": "Limpiar virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Sirve para descubrir qué ha pasado tras un incidente y quién ha sido."},
    {"text": "¿Qué es la 'Cadena de Custodia'?", "option_a": "Una cadena de oro", "option_b": "Registro detallado de todas las personas que han custodiado la evidencia digital para asegurar su validez en un juicio", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "hard", "explanation": "Si se rompe, la prueba puede ser invalidada ante un juez."},
    {"text": "¿Qué es un 'Write Blocker' forense?", "option_a": "Un antivirus", "option_b": "Dispositivo que impide cualquier escritura en el disco analizado para no contaminar la evidencia", "option_c": "Un manual de red", "option_d": "Un tipo de cable", "correct_answer": "b", "difficulty": "hard", "explanation": "Garantiza que la copia forense es idéntica al original."},
    {"text": "¿Qué es el 'Data Retention Policy'?", "option_a": "Borrar fotos", "option_b": "Política que define cuánto tiempo debe guardarse cada tipo de dato por motivos legales o de negocio", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Es vital por ley (ej: facturas 5 años, logs 1 año...)."},
    {"text": "¿Qué es el 'Data Shredding'?", "option_a": "Papelera de reciclaje", "option_b": "Destrucción segura e irreversible de datos (físicos o digitales) para que no puedan ser recuperados", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Obligatorio para documentos con PII al final de su vida útil."},
    {"text": "¿Qué es el 'GDPR' (RGPD)?", "option_a": "Un virus europeo", "option_b": "Reglamento general de protección de datos de la UE, el más estricto del mundo", "option_c": "Un antivirus", "option_d": "Un manual de Linux", "correct_answer": "b", "difficulty": "easy", "explanation": "Otorga a los ciudadanos un gran control sobre su privacidad digital."},
    {"text": "¿Qué es el 'PCI-DSS'?", "option_a": "Protocolo de red bancaria", "option_b": "Estándar de seguridad para todas las empresas que manejan tarjetas de crédito", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Payment Card Industry Data Security Standard."},
    {"text": "¿Qué es la 'Cibercriminología'?", "option_a": "Hackear criminales", "option_b": "Estudio del comportamiento, causas y motivaciones de los criminales en el entorno digital", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Ayuda a entender por qué y cómo atacan los hackers."},
    {"text": "¿Qué es un 'Ethical Hacker' (Hacker Ético)?", "option_a": "Un hacker bueno", "option_b": "Profesional que usa sus habilidades para encontrar fallos y ayudar a las empresas a protegerse", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "easy", "explanation": "También llamados White Hats."},
