    {"text": "¿Qué es el 'Lockbit'?", "option_a": "Un antivirus", "option_b": "Uno de los grupos de ransomware (y el software que usan) más activos y peligrosos de los últimos años", "option_c": "Un tipo de router", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Operan bajo un modelo de 'Ransomware-as-a-Service'."},
    {"text": "¿Qué es un 'Botnet Master'?", "option_a": "Un juego de robots", "option_b": "Persona que controla y gestiona una botnet de miles de ordenadores infectados", "option_c": "Un virus", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "También llamado 'herder' o pastor de zombis."},
    {"text": "¿Qué es el 'Dark Web'?", "option_a": "Internet oscuro", "option_b": "Parte de internet accesible solo con software especial (como Tor), donde se comercia con datos robados", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Es donde los hackers venden las bases de datos y herramientas maliciosas."},
