    {"text": "¿Qué es un 'Insider Threat' (Amenaza Interna)?", "option_a": "Un virus dentro del PC", "option_b": "Riesgo provocado por empleados o colaboradores de la propia empresa (por malicia o error)", "option_c": "Un manual", "option_d": "Un antivirus potente", "correct_answer": "b", "difficulty": "easy", "explanation": "Es uno de los riesgos más difíciles de detectar porque ya tienen acceso legítimo."},
    {"text": "¿Qué es el 'Whaling'?", "option_a": "Pescar ballenas", "option_b": "Phishing dirigido contra altos directivos para robar grandes sumas de dinero", "option_c": "Un virus", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "easy", "explanation": "Ejemplo: fingir una orden del CEO para una transferencia urgente."},
    {"text": "¿Qué es el 'Ransomware-as-a-Service' (RaaS)?", "option_a": "Alquilar un antivirus", "option_b": "Modelo de negocio donde desarrolladores de ransomware alquilan su virus a otros criminales a cambio de una comisión", "option_c": "Un manual de Linux", "option_d": "Un tipo de router", "correct_answer": "b", "difficulty": "medium", "explanation": "Ha provocado una explosión de ataques en todo el mundo."},
    {"text": "¿Qué es el 'Phishing-as-a-Service' (PhaaS)?", "option_a": "Hackear gratis", "option_b": "Plataformas que permiten a cualquiera lanzar campañas de Phishing profesionales pagando una suscripción", "option_c": "Un virus de red", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Reduce la barrera de entrada para nuevos criminales."},
    {"text": "¿Qué es un 'Command and Control' (C2)?", "option_a": "El jefe de la red", "option_b": "Servidor central desde donde un atacante envía órdenes a sus miles de equipos infectados", "option_c": "Un virus de BIOS", "option_d": "Un manual de red", "correct_answer": "b", "difficulty": "medium", "explanation": "Cortar la conexión con el C2 inutiliza la botnet."},
    {"text": "¿Qué es un 'Zero-Knowledge Proof'?", "option_a": "No saber nada", "option_b": "Método criptográfico para demostrar que conoces un secreto sin revelar el secreto en sí", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "hard", "explanation": "Fundamental para la privacidad moderna en Blockchain e Identidad Digital."},
    {"text": "¿Qué es un 'Digital Watermark'?", "option_a": "Marca de agua digital", "option_b": "Información oculta en un archivo multimedia para identificar su origen y derechos de autor", "option_c": "Un virus de red", "option_d": "Un manual", "correct_answer": "b", "difficulty": "easy", "explanation": "Sirve para rastrear filtraciones de películas o documentos privados."},
    {"text": "Final batch completed for Ciberseguridad.", "option_a": "Ok", "option_b": "Felicidades", "option_c": "Buen trabajo", "option_d": "Siguiente subject", "correct_answer": "c", "difficulty": "easy", "explanation": "Has completado las 300 preguntas de Ciberseguridad."},
    {"text": "¿Qué es el 'Degaussing'?", "option_a": "Limpiar el PC", "option_b": "Eliminar datos de soportes magnéticos (como HDDs) mediante un potente campo magnético", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "medium", "explanation": "Inutiliza el disco físicamente al borrar su estructura magnética."},
    {"text": "¿Qué es un 'Mantrap'?", "option_a": "Una trampa para ratones", "option_b": "Sistema de dos puertas donde la segunda no abre hasta que la primera se cierra, para control de acceso físico", "option_c": "Un virus de red", "option_d": "Un antivirus potente", "correct_answer": "b", "difficulty": "medium", "explanation": "Evita el 'Tailgating' (que alguien se cuele detrás de ti)."},
    {"text": "¿Qué es el 'Piggybacking' o 'Tailgating'?", "option_a": "Ir en bici", "option_b": "Entrar a una zona restringida siguiendo a una persona autorizada sin usar tus propias credenciales", "option_c": "Un virus de BIOS", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Fallo de seguridad física muy común basado en la cortesía humana."},
    {"text": "¿Qué es un 'Smart Card'?", "option_a": "Una tarjeta inteligente", "option_b": "Tarjeta con un chip integrado que almacena certificados y claves para autenticación fuerte", "option_c": "Un virus de red", "option_d": "Un tipo de monitor", "correct_answer": "b", "difficulty": "easy", "explanation": "Usada a menudo junto con un PIN (MFA)."},
    {"text": "¿Qué es la 'Biometría Fisiológica'?", "option_a": "Medir el PC", "option_b": "Uso de rasgos físicos únicos (huella, iris, cara) para identificar a una persona", "option_c": "Un virus de red", "option_d": "Un manual de ayuda", "correct_answer": "b", "difficulty": "easy", "explanation": "Algo que 'eres'."},
    {"text": "¿Qué es la 'Biometría de Comportamiento'?", "option_a": "Ver cómo te portas", "option_b": "Identificación basada en patrones de conducta (forma de escribir, caminar o usar el ratón)", "option_c": "Un virus", "option_d": "Un antivirus", "correct_answer": "b", "difficulty": "medium", "explanation": "Muy difícil de imitar por un atacante."},
